const item = $input.first().json;
const pref = item.model_preference || 'fast';

let primary = "meta-llama/llama-3.3-70b-instruct:free";
let failover = "google/gemini-2.5-pro:free";
let is_embedding = false;

if (pref === 'large-context') {
  primary = "google/gemini-2.5-pro:free";
  failover = "meta-llama/llama-3.3-70b-instruct:free";
} else if (pref === 'embedding') {
  primary = "sentence-transformers/all-MiniLM-L6-v2";
  failover = null;
  is_embedding = true;
}

return {
  json: {
    ...item,
    primary_model: primary,
    failover_model: failover,
    is_embedding: is_embedding,
    start_time: Date.now()
  }
};

const item = $input.first().json;
const body = {
  model: item.primary_model,
  messages: [
    { role: "system", content: item.system_message || "You are a helpful assistant." },
    { role: "user", content: item.prompt }
  ]
};

if (item.max_tokens) {
  body.max_tokens = item.max_tokens;
}

if (item.output_format === 'json') {
  body.response_format = { type: "json_object" };
}

return { json: { ...item, request_body: body } };

const orig = $('Select Model').first().json;
const body = {
  model: orig.failover_model,
  messages: [
    { role: "system", content: orig.system_message || "You are a helpful assistant." },
    { role: "user", content: orig.prompt }
  ]
};

if (orig.max_tokens) {
  body.max_tokens = orig.max_tokens;
}

if (orig.output_format === 'json') {
  body.response_format = { type: "json_object" };
}

return { json: { ...orig, request_body: body } };

const original = $('Select Model').first().json;
const httpData = $input.first().json;

let aiOutput = '';
let promptTokens = 0;
let completionTokens = 0;
let modelUsed = original.primary_model;

if (original.is_embedding) {
  aiOutput = httpData; 
} else {
  const failoverItems = $('Chat Completion Failover').all();
  if (failoverItems && failoverItems.length > 0) {
    modelUsed = original.failover_model;
  }

  if (httpData.choices && httpData.choices.length > 0) {
    aiOutput = httpData.choices[0].message.content;
    promptTokens = httpData.usage ? httpData.usage.prompt_tokens : 0;
    completionTokens = httpData.usage ? httpData.usage.completion_tokens : 0;
  } else {
    aiOutput = "ERROR: " + JSON.stringify(httpData);
  }
}

const latencyMs = Date.now() - original.start_time;

return {
  json: {
    ...original,
    response: aiOutput,
    model_used: modelUsed,
    tokens_input: promptTokens,
    tokens_output: completionTokens,
    latency_ms: latencyMs,
    cost_usd: 0.00,
    workflow_name: "UTIL__AICall",
    log_type: "ai_call",
    action: original.is_embedding ? "ai_embedding" : "ai_completion",
    input_payload: original.prompt
  }
};

const calcData = $('Calculate Usage').first().json;

return {
  json: {
    response: calcData.response,
    model_used: calcData.model_used,
    tokens_input: calcData.tokens_input,
    tokens_output: calcData.tokens_output,
    latency_ms: calcData.latency_ms,
    cost_usd: calcData.cost_usd
  }
};
